/**
 * @fileoverview SPA Component base class — lifecycle, reactive state,
 *               virtual-DOM rendering, and event-bus integration.
 * @module module/SPA/component
 */

import { h, createElement, patch } from './vdom.js';
import { bus } from './event-bus.js';

/**
 * Base class for SPA components.
 *
 * Subclass and override `render()` to return a VNode tree via `h()`.
 * Call `this.setState(partial)` to trigger a re-render.
 *
 * Lifecycle hooks (override to use):
 *   - `setup()`      — called once before first render (sync)
 *   - `onMount()`    — called after first DOM insertion
 *   - `onUpdate()`   — called after each re-render (not the first)
 *   - `onUnmount()`  — called when the component is removed from DOM
 *
 * @example
 * class Counter extends Component {
 *     setup() { this.state = { count: 0 }; }
 *     render() {
 *         return h('button', { onClick: () => this.setState({ count: this.state.count + 1 }) },
 *             `Clicked ${this.state.count} times`
 *         );
 *     }
 * }
 */
export class Component {
    /** @type {object} — reactive state (plain object) */
    state = {};
    /** @type {object} — immutable props passed from parent/router */
    props = {};
    /** @type {HTMLElement|null} — root DOM node */
    _el = null;
    /** @type {object|null} — previous VNode tree */
    _vnode = null;
    /** @type {boolean} */
    _mounted = false;
    /** @type {Array<() => void>} — cleanup callbacks (event subscriptions, timers, etc.) */
    _cleanups = [];

    /**
     * @param {object} [props]
     */
    constructor(props = {}) {
        this.props = Object.freeze({ ...props });
        this.setup();
    }

    // ── Lifecycle hooks (override in subclass) ───

    /** Called once before the first render. Set initial state here. */
    setup() {}

    /** Called after the component is inserted into the DOM. */
    onMount() {}

    /** Called after every re-render (not on first mount). */
    onUpdate() {}

    /** Called when the component is removed from the DOM. */
    onUnmount() {}

    // ── Rendering ────────────────────────────────

    /**
     * Return a VNode tree describing the component's DOM.
     * **Must** be overridden by subclasses.
     * @returns {object} VNode
     */
    render() {
        return h('div');
    }

    /**
     * Merge `partial` into `this.state` and schedule a re-render.
     * @param {object|Function} partial — object to merge, or `(prev) => partial`
     */
    setState(partial) {
        if (typeof partial === 'function') partial = partial(this.state);
        Object.assign(this.state, partial);
        this._rerender();
    }

    // ── Internal rendering pipeline ──────────────

    /**
     * Perform the initial render and mount into a container.
     * @param {HTMLElement} container
     */
    _mount(container) {
        const vnode = this.render();
        const el = createElement(vnode);
        container.appendChild(el);
        this._el = el;
        this._vnode = vnode;
        this._mounted = true;
        this.onMount();
    }

    /** Re-render: diff the old and new VNode trees, then patch the real DOM. */
    _rerender() {
        if (!this._mounted || !this._el) return;
        const next = this.render();
        const parent = this._el.parentNode;
        if (!parent) return;

        const index = Array.prototype.indexOf.call(parent.childNodes, this._el);
        patch(parent, this._vnode, next, index);

        // After patch the child at `index` may have been replaced
        this._el = parent.childNodes[index];
        this._vnode = next;
        this.onUpdate();
    }

    /** Remove the component from the DOM and run cleanup. */
    _unmount() {
        this.onUnmount();
        this._mounted = false;
        for (const fn of this._cleanups) fn();
        this._cleanups.length = 0;
        if (this._el && this._el.parentNode) {
            this._el.parentNode.removeChild(this._el);
        }
        this._el = null;
        this._vnode = null;
    }

    // ── Event-bus shorthand ──────────────────────

    /**
     * Subscribe to a global event (auto-unsubscribed on unmount).
     * @param {string} event
     * @param {Function} handler
     */
    $on(event, handler) {
        const off = bus.on(event, handler);
        this._cleanups.push(off);
    }

    /**
     * Emit a global event.
     * @param {string} event
     * @param {...*} args
     */
    $emit(event, ...args) {
        bus.emit(event, ...args);
    }
}

export { h };
